I was able to make it work with a hack (bypassing all the cpu detection stuff) on the [hashes](https://github.com/RustCrypto/hashes.git) project:
```
diff --git a/sha2/src/sha512/x86.rs b/sha2/src/sha512/x86.rs
index bb79040..0d739d5 100644
--- a/sha2/src/sha512/x86.rs
+++ b/sha2/src/sha512/x86.rs
@@ -16,13 +16,13 @@ cpufeatures::new!(avx2_cpuid, "avx2");
 pub fn compress(state: &mut [u64; 8], blocks: &[[u8; 128]]) {
     // TODO: Replace with https://github.com/rust-lang/rfcs/pull/2725
     // after stabilization
-    if avx2_cpuid::get() {
-        unsafe {
-            sha512_compress_x86_64_avx2(state, blocks);
-        }
-    } else {
+    //if avx2_cpuid::get() {
+      //  unsafe {
+     //       sha512_compress_x86_64_avx2(state, blocks);
+      //  }
+   // } else {
         super::soft::compress(state, blocks);
-    }
+    //}
 }
```

Then changing the ```Cargo.toml``` in the netavark project to point to the local project

```
-sha2 = "0.10.6"
+sha2 = {path ="../hashes/sha2"}
```
